const p = $input.first().json;
// Raw Notion page object: id + properties. Status may be a 'status'- or 'select'-type property.
const props = p.properties || {};
const statusProp = props.Status || props.status || {};
const status = (statusProp.status && statusProp.status.name) || (statusProp.select && statusProp.select.name) || '';
const titleArr = (props.Name && props.Name.title) || (props.Title && props.Title.title) || [];
const page_title = titleArr.map(t => t.plain_text).join('') || '(untitled)';
const page_id = p.id;
// Only compliance-review states proceed. Anything else is a no-op skip (not an error).
const reviewable = (status === 'Draft' || status === 'In Review');
return [{ json: { page_id, page_title, status, _skip: !reviewable, skip_reason: reviewable ? '' : 'status_not_reviewable' } }];

