// Deterministic. The LLM never decides publish vs hold.
const base = $('Assemble Draft + Load Context Layer').first().json;
if (base._needs_content) {
  return [{ json: { page_id: base.page_id, page_title: base.page_title, compliance_status: 'Needs Content',
    audit_comment: 'This page has no draft body to review yet.', claims_checked: 0, unsupported: [], verdicts: [],
    context_stale: !!base.context_stale, context_age_days: base.context_age_days } }];
}
// Agent output lands in $json.output (parsed by the Structured Output Parser). Defensive read.
const agentJson = $('Compliance Governance Agent').first().json;
const parsed = (agentJson && agentJson.output) || agentJson || {};
const verdicts = Array.isArray(parsed) ? parsed : (parsed.verdicts || []);
const unsupported = verdicts.filter(v => v && v.verdict !== 'supported');
const stale = !!base.context_stale;
// Any non-supported claim OR stale context forces Needs Review.
const status = (unsupported.length > 0 || stale) ? 'Needs Review' : 'Ready';
// Build a scannable Notion annotation (ASCII hyphens only - anti-AI-tell discipline).
const srcMap = { prior_publication: 'prior published post', context_layer: 'fact layer', approved_claim: 'approved-claims list', none: 'no source' };
const lines = [];
lines.push(`Compliance gate: ${status}  (${verdicts.length} claims checked)`);
if (stale) lines.push(`- WARNING context layer is ${base.context_age_days} days old (>30) - forced to review.`);
for (const v of unsupported) {
  const ev = (v.evidence || '').slice(0, 240);
  const src = srcMap[v.source] || v.source || 'no source';
  lines.push(`- [${v.risk_category || 'unverified'}] ${v.verdict}: "${v.claim}"  |  ${src}: ${ev}`);
}
if (!unsupported.length && !stale) lines.push('- All claims trace to an approved source. Cleared for a human to publish.');
const audit_comment = lines.join('\n');
return [{ json: { page_id: base.page_id, page_title: base.page_title, compliance_status: status,
  audit_comment, claims_checked: verdicts.length, unsupported, verdicts,
  context_stale: stale, context_age_days: base.context_age_days } }];

const dec = $('Parent - Decide Ready / Needs Review').first().json;
// Native agent: per-stage token/cost is coarser than the HTTP+Code build (accepted tradeoff).
// Try to surface any usage the agent exposes; total run usage otherwise lives in n8n's execution metadata.
let token_usage = null;
try { const a = $('Compliance Governance Agent').first().json; token_usage = (a && (a.tokenUsage || (a.output && a.output.usage))) || null; } catch (e) {}
const verification_report = {
  compliance_status: dec.compliance_status,
  claims_checked: dec.claims_checked || 0,
  unsupported: dec.unsupported || [],
  verdicts: dec.verdicts || [],
  context_stale: !!dec.context_stale,
  context_age_days: dec.context_age_days,
  token_usage,
  observability_note: 'Native AI Agent: per-stage token/cost is coarser than the HTTP+Code backup. Total run usage is in the n8n execution metadata; a production tap would emit it to the telemetry store.',
};
return [{ json: { page_id: dec.page_id, page_title: dec.page_title, compliance_status: dec.compliance_status, audit_comment: dec.audit_comment, verification_report } }];
